    if (!username || !password) {
      Alert.alert('Missing fields', 'Please enter username and password');
      return;
    }

    await AsyncStorage.multiSet([
      [USERNAME_KEY, username],
      [PASSWORD_KEY, password],
      [AUTH_FLAG_KEY, 'true'],
    ]);
