function HomeScreen({ onLogout }) {
  const handleLogout = async () => {
    await AsyncStorage.removeItem(AUTH_FLAG_KEY);
    onLogout();
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', padding: 24 }}>
      <Text style={{ fontSize: 24, marginBottom: 16 }}>Welcome</Text>
      <Button title="Logout" onPress={handleLogout} />
    </View>
  );
}

export default function App() {
  const [loading, setLoading] = useState(true);
  const [authenticated, setAuthenticated] = useState(false);

  useEffect(() => {
    (async () => {
      const flag = await AsyncStorage.getItem(AUTH_FLAG_KEY);
      setAuthenticated(flag === 'true');
      setLoading(false);
    })();
  }, []);

  if (loading) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <ActivityIndicator />
      </View>
    );
  }

  return authenticated ? (
    <HomeScreen onLogout={() => setAuthenticated(false)} />
  ) : (
    <LoginScreen onLoginSuccess={() => setAuthenticated(true)} />
  );
}